prompt --application/shared_components/navigation/lists/navigation_dynamic
begin
wwv_flow_imp_shared.create_list(
 p_id=>wwv_flow_imp.id(17248635413596748)
,p_name=>'Navigation Dynamic'
,p_list_type=>'SQL_QUERY'
,p_list_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ''Dashboard''                 AS label,',
'       ''f?p=&APP_ID.:1:&SESSION.''  AS target,',
'       0                           AS is_current,',
'       ''fa-dashboard''              AS icon',
'FROM dual',
'UNION ALL',
'SELECT ''Return Cases'',',
'       ''f?p=&APP_ID.:2:&SESSION.'',',
'       0, ''fa-inbox''',
'FROM   return_case',
'WHERE  case_status NOT IN (''FULFILLED'',''CLOSED'',''REJECTED'')',
'UNION ALL',
'SELECT ''Approvals'',',
'       ''f?p=&APP_ID.:3:&SESSION.'',',
'       0, ''fa-check-square''',
'FROM   return_case',
'WHERE  case_status = ''PENDING_APPROVAL''',
''))
,p_list_status=>'PUBLIC'
,p_version_scn=>39140299832231
);
end;
