'-- Source for the KPI Cards region (4 tiles, one row each)',
'SELECT 1 AS kpi_id,',
'       ''Open Cases''                                             AS card_title,',
'       TO_CHAR(COUNT(*), ''FM999G999'')                          AS card_subtitle,',
'       ''fa-inbox''                                               AS card_icon,',
'       NULL                                                     AS card_text,',
'       NULL                                                     AS card_subtext,',
'      get_sparkline_data(''OPEN'')         AS card_body',
'FROM   return_case',
'WHERE  case_status NOT IN (''FULFILLED'', ''CLOSED'', ''REJECTED'')',
'UNION ALL',
'SELECT 2,',
'       ''Pending Approval'',',
'       TO_CHAR(COUNT(*), ''FM999G999''),',
'       ''fa-hourglass-o'', NULL, NULL, get_sparkline_data(''PENDING_APPROVAL'')',
'FROM   return_case',
'WHERE  case_status = ''PENDING_APPROVAL''',
'UNION ALL',
'SELECT 3,',
'       ''Closed Today'',',
'       TO_CHAR(COUNT(*), ''FM999G999''),',
'       ''fa-check-circle'', NULL, NULL,get_sparkline_data(''CLOSED'')',
'FROM   return_case',
'WHERE  case_status = ''CLOSED''',
'AND    TRUNC(updated_on) = TRUNC(SYSDATE)',
'UNION ALL',
'SELECT 4,',
'       ''Cases Today'',',
'       TO_CHAR(COUNT(*), ''FM999G999''),',
'       ''fa-calendar-o'', NULL, NULL,null',
'FROM   return_case',
'WHERE  TRUNC(created_on) = TRUNC(SYSDATE)',
'ORDER BY 1;'))
