'SELECT',
'    rc.return_case_id,',
'    rc.rma_number,',
'    c.first_name || '' '' || c.last_name          AS customer_name,',
'    c.mobile_phone,',
'    so.order_number,',
'    so.order_total,',
'    so.currency,',
'    rc.reason_code,',
'    INITCAP(REPLACE(rc.reason_code, ''_'', '' ''))  AS reason_label,',
'    rc.customer_description,',
'    rc.requested_resolution,',
'    rc.channel,',
'    ROUND((SYSDATE - CAST(rc.created_on AS DATE)) * 24, 1) AS hours_waiting,',
'    rc.created_on',
'FROM   return_case  rc',
'JOIN   customer     c  ON c.customer_id = rc.customer_id',
'LEFT JOIN sales_order so ON so.order_id = rc.order_id',
'WHERE  rc.case_status            = ''PENDING_APPROVAL''',
'AND    rc.approval_required_flag = ''Y''',
'ORDER BY rc.created_on ASC',
''))
