,p_event_id=>wwv_flow_imp.id(17240863033840307)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'function animateCount(el, target, duration) {',
'  var start = performance.now();',
'  (function tick(now) {',
'    var progress = Math.min((now - start) / duration, 1);',
'    var eased    = 1 - Math.pow(1 - progress, 3);',
'    el.text(Math.round(eased * target));',
'    if (progress < 1) requestAnimationFrame(tick);',
'  })(start);',
'}',
'',
'apex.jQuery(".a-CardView-mainContent").each(function() {',
'  var el   = apex.jQuery(this);',
'  var text = el.text().trim();',
'  if (text.indexOf('','') === -1) return;',
'',
'  try {',
'    var data = text.split('','').map(Number);',
'    var max  = Math.max.apply(null, data) || 1;',
'    var w = 120, h = 40, pad = 4, n = data.length;',
'',
'    var card       = el.closest(''.a-CardView-card, .a-CardView-item, .a-Card'');',
'    var subtitleEl = card.find(''.a-CardView-subTitle, .a-CardView-subtitle'').first();',
'',
'    var countTarget = parseInt(subtitleEl.text().replace(/[^0-9]/g, ''''), 10);',
'    if (!isNaN(countTarget)) {',
'      subtitleEl.text(''0'');',
'      animateCount(subtitleEl, countTarget, 1400);',
'    }',
'',
'    card.find(''.spark-trend'').remove();',
'    var diff = data[n - 1] - data[0];',
'    var trendClass, trendLabel;',
unistr('    if (diff > 0)      { trendClass = ''spark-trend--up'';   trendLabel = ''\25B2 +'' + diff; }'),
unistr('    else if (diff < 0) { trendClass = ''spark-trend--down''; trendLabel = ''\25BC ''  + diff; }'),
unistr('    else               { trendClass = ''spark-trend--flat''; trendLabel = ''\2192 0''; }'),
'    subtitleEl.after(''<span class="spark-trend '' + trendClass + ''">'' + trendLabel + ''</span>'');',
'',
'    var iconEl = card.find(''.a-CardView-iconWrap, .a-CardView-iconBadge, .a-CardView-icon'').first();',
'    var color  = ''#4a90d9'';',
'    if (iconEl.length) {',
'      var bg = window.getComputedStyle(iconEl[0]).backgroundColor;',
'      if (bg && bg !== ''transparent'' && bg !== ''rgba(0, 0, 0, 0)'') color = bg;',
'    }',
'',
'    var pts = data.map(function(v, i) {',
'      return {',
'        x: +(i * w / (n - 1)).toFixed(2),',
'        y: +(h - pad - (v / max * (h - pad * 2))).toFixed(2)',
'      };',
'    });',
'',
'    var linePath = pts.map(function(p, i) {',
'      return (i === 0 ? ''M'' : ''L'') + p.x + '','' + p.y;',
'    }).join('' '');',
'',
'    var areaPath = linePath + '' L'' + pts[n-1].x + '','' + h + '' L0,'' + h + '' Z'';',
'    var last = pts[n - 1];',
'    var uid  = ''sg'' + Math.random().toString(36).substr(2, 5);',
'',
'    el.html(',
'      ''<svg width="'' + w + ''" height="'' + h +',
'           ''" viewBox="0 0 '' + w + '' '' + h + ''" overflow="visible">'' +',
'        ''<defs><linearGradient id="'' + uid + ''" x1="0" y1="0" x2="0" y2="1">'' +',
'          ''<stop offset="0%"   stop-color="'' + color + ''" stop-opacity="0.3"/>'' +',
'          ''<stop offset="100%" stop-color="'' + color + ''" stop-opacity="0"/>'' +',
'        ''</linearGradient></defs>'' +',
'        ''<path d="'' + areaPath + ''" fill="url(#'' + uid + '')"/>'' +',
'        ''<path class="spark-path" d="'' + linePath + ''" fill="none" stroke="'' + color + ''"'' +',
'             '' stroke-width="2" stroke-linecap="round" stroke-linejoin="round" opacity="0.85"/>'' +',
'        ''<circle cx="'' + last.x + ''" cy="'' + last.y + ''" r="3" fill="'' + color + ''" opacity="0.9">'' +',
'          ''<animate attributeName="r"       values="2;5;2" dur="2s" repeatCount="indefinite"/>'' +',
'          ''<animate attributeName="opacity" values="0.9;0.3;0.9" dur="2s" repeatCount="indefinite"/>'' +',
'        ''</circle>'' +',
'      ''</svg>''',
'    );',
'',
'    var pathEl = el.find(''.spark-path'')[0];',
'    if (pathEl && pathEl.getTotalLength) {',
'      var len = pathEl.getTotalLength();',
'      pathEl.style.strokeDasharray  = len;',
'      pathEl.style.strokeDashoffset = len;',
'      requestAnimationFrame(function() {',
'        requestAnimationFrame(function() {',
'          pathEl.style.transition       = ''stroke-dashoffset 2s ease-out'';',
'          pathEl.style.strokeDashoffset = 0;',
'        });',
'      });',
'    }',
'',
'  } catch(e) { console.log("sparkline error:", e.message); }',
'});'))
);
end;
/
