begin
wwv_flow_imp_page.create_page(
 p_id=>3
,p_name=>'Return Case Detail'
,p_alias=>'RETURN-CASE-DETAIL'
,p_step_title=>'Return Case Detail'
,p_autocomplete_on_off=>'OFF'
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
'.rma-app .rma-case-hero {',
'  padding: 20px 24px;',
'  display: flex;',
'  align-items: center;',
'  justify-content: space-between;',
'}',
'.rma-app .rma-case-hero .t-Region-header {',
'  border-bottom: none;',
'  padding: 0;',
'  flex: 1;',
'}',
'',
'.rma-app .rma-case-hero .t-Region-body {',
'  display: flex;',
'  align-items: center;',
'  justify-content: space-between;',
'  padding: 16px 20px 16px 28px;  /* increase right padding if still clipping */',
'  gap: 12px;',
'}',
'',
'.rma-app .rma-case-hero {',
'  overflow: visible;',
'}',
'',
'',
'',
'.rma-app .rma-case-hero .t-Region-body {',
'  display: flex;',
'  align-items: center;',
'  justify-content: space-between;',
'  padding: 16px 20px;',
'  gap: 12px;',
'}',
'',
unistr('/* The scrollable feed container \2014 WhatsApp light theme background */'),
'.wa-feed {',
'  background:     #E5DDD5;',
'  border-radius:  8px;',
'  padding:        16px 12px;',
'  min-height:     400px;',
'  max-height:     560px;',
'  overflow-y:     auto;',
'  display:        flex;',
'  flex-direction: column;',
'  gap:            6px;',
'}',
'',
'/* Each row spans full width; the bubble inside aligns itself */',
'.wa-row {',
'  display: flex;',
'  width:   100%;',
'}',
'',
unistr('/* Inbound: customer message, left-aligned \2014 WhatsApp green */'),
'.wa-bubble-in {',
'  background:    #D9FDD3;',
'  color:         #111B21;',
'  border-radius: 0 8px 8px 8px;              /* flat top-left corner */',
'  padding:       8px 12px 4px;',
'  max-width:     65%;',
'  margin-right:  auto;                        /* pushes bubble to left */',
'  box-shadow:    0 1px 2px rgba(0,0,0,0.1);',
'}',
'',
unistr('/* Outbound: agent or AI reply, right-aligned \2014 white */'),
'.wa-bubble-out {',
'  background:    #FFFFFF;',
'  color:         #111B21;',
'  border-radius: 8px 0 8px 8px;              /* flat top-right corner */',
'  padding:       8px 12px 4px;',
'  max-width:     65%;',
'  margin-left:   auto;                        /* pushes bubble to right */',
'  box-shadow:    0 1px 2px rgba(0,0,0,0.1);',
'}',
'',
'.wa-text {',
'  font-size:   14px;',
'  line-height: 1.45;',
'  word-wrap:   break-word;',
'  white-space: pre-wrap;                      /* preserves line breaks in messages */',
'}',
'',
'.wa-meta {',
'  font-size:  11px;',
'  color:      #667781;',
'  text-align: right;',
'  margin-top: 4px;',
'}',
'.appr-seal{',
'  display:inline-flex; align-items:center; gap:8px;',
'  padding:8px 14px; border:2.5px solid currentColor; border-radius:8px;',
'  font-size:15px; font-weight:800; letter-spacing:.08em; text-transform:uppercase;',
'  transform: rotate(-7deg); opacity:.9;',
'  box-shadow: inset 0 0 0 1.5px currentColor; /* double-stroke stamp look */',
'}',
'.appr-seal .ico{ display:none; }   /* stamp reads on the word alone */',
'.appr-approved{ color: oklch(0.52 0.14 160); }',
'.appr-rejected{ color: oklch(0.54 0.17 25); }',
'.appr-pending { color: oklch(0.52 0.11 75); }',
'.appr-none    { display:none; }'))
,p_page_css_classes=>'rma-app'
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'02'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(16185734624671786)
,p_plug_name=>'Return Case Detail'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>4501440665235496320
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'   c.customer_id,',
'    rc.return_case_id,',
'    rc.rma_number,',
'    CASE rc.case_status',
'        WHEN ''OPEN''             THEN ''New''',
'        WHEN ''PENDING_EVIDENCE'' THEN ''Awaiting Evidence''',
'        WHEN ''PENDING_APPROVAL'' THEN ''Needs Approval''',
'        WHEN ''APPROVED''         THEN ''Approved''',
'        WHEN ''REJECTED''         THEN ''Rejected''',
'        WHEN ''FULFILLED''        THEN ''Fulfilled''',
'        WHEN ''CLOSED''           THEN ''Closed''',
'        ELSE rc.case_status',
'    END                                         AS status_label,',
'    CASE rc.case_status',
'         WHEN ''OPEN''             THEN ''blue''',
'         WHEN ''PENDING_EVIDENCE'' THEN ''amber''',
'         WHEN ''PENDING_APPROVAL'' THEN ''amber''',
'         WHEN ''APPROVED''         THEN ''primary''',
'         WHEN ''FULFILLED''        THEN ''primary''',
'         WHEN ''REJECTED''         THEN ''rose''',
'         WHEN ''CLOSED''           THEN ''blue''',
'         ELSE ''blue''',
'       END AS status_class,',
'    rc.case_status,',
'    c.first_name || '' '' || c.last_name          AS customer_name,',
'    c.mobile_phone,',
'    c.email,',
'    so.order_number,',
'    so.order_total,',
'    rc.reason_code,',
'    INITCAP(REPLACE(rc.reason_code, ''_'', '' ''))  AS reason_label,',
'    rc.requested_resolution,',
'    rc.channel,',
'    rc.approval_required_flag,',
'    rc.created_on,',
'    rc.updated_on,',
'    ROUND((SYSDATE - CAST(rc.created_on AS DATE)) * 24, 1) AS hours_open,',
'    CASE approval_status',
'  WHEN ''APPROVED'' THEN ''approved''',
'  WHEN ''REJECTED'' THEN ''rejected''',
'  WHEN ''PENDING''  THEN ''pending''',
'  ELSE ''none''',
'END approval_status,',
'CASE approval_status',
'  WHEN ''APPROVED'' THEN ''Approved''',
'  WHEN ''REJECTED'' THEN ''Rejected''',
'  WHEN ''PENDING''  THEN ''Pending review''',
'  ELSE NULL',
'END approval_label',
'FROM   return_case  rc',
'JOIN   customer     c  ON c.customer_id = rc.customer_id',
'LEFT JOIN sales_order so ON so.order_id = rc.order_id'))
,p_is_editable=>true
,p_edit_operations=>'i:u:d'
,p_lost_update_check_type=>'VALUES'
,p_plug_source_type=>'NATIVE_FORM'
);
