 p_id=>wwv_flow_imp.id(16225804669622136)
,p_name=>'Audit Timeline'
,p_template=>4072358936313175081
,p_display_sequence=>900
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    we.event_type,',
'    INITCAP(REPLACE(we.event_type, ''_'', '' ''))   AS event_label,',
'    we.event_source,',
'    we.outcome_status,',
'    we.correlation_id,',
'    we.error_message,',
'    we.created_on',
'FROM   workflow_event we',
'WHERE  (',
'           (we.related_entity_type = ''RETURN_CASE''  AND we.related_entity_id = :P3_RETURN_CASE_ID)',
'        OR (we.related_entity_type = ''CONVERSATION''',
'            AND we.related_entity_id = (',
'                SELECT conversation_id FROM return_case',
'                WHERE  return_case_id = :P3_RETURN_CASE_ID))',
'       )',
'ORDER BY we.created_on DESC;'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
,p_query_row_template=>2538654340625403440
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_num_rows_type=>'NEXT_PREVIOUS_LINKS'
,p_pagination_display_position=>'BOTTOM_RIGHT'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
);
