wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(10477192859131817)
,p_name=>'Case Header'
,p_parent_plug_id=>wwv_flow_imp.id(18011553836415405)
,p_template=>4072358936313175081
,p_display_sequence=>10
,p_region_template_options=>'#DEFAULT#:t-Region--accent1:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_display_point=>'SUB_REGIONS'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    rc.rma_number,',
'    rc.case_status,',
'    CASE rc.case_status',
'        WHEN ''OPEN''             THEN ''u-color-15''   -- blue',
'        WHEN ''PENDING_APPROVAL'' THEN ''u-color-14''   -- orange',
'        WHEN ''APPROVED''         THEN ''u-color-13''   -- green',
'        WHEN ''REJECTED''         THEN ''u-color-12''   -- red',
'        WHEN ''FULFILLED''        THEN ''u-color-13''   -- green',
'        ELSE                         ''u-color-1''',
'    END                                             AS status_css,',
'    c.first_name || '' '' || c.last_name             AS customer_name,',
'    c.mobile_phone,',
'    c.email,',
'    so.order_number,',
'    so.order_date,',
'    so.delivery_date,',
'    so.order_total,',
'    so.currency,',
'    rc.channel,',
'    rc.reason_code,',
'    INITCAP(REPLACE(rc.reason_code, ''_'', '' ''))     AS reason_label,',
'    rc.customer_description,',
'    rc.requested_resolution,',
'    rc.final_resolution,',
'    rc.approval_required_flag,',
'    rc.approval_status,',
'    rc.created_on,',
'    rc.updated_on,',
'    rc.created_by_source',
'FROM   return_case  rc',
'JOIN   customer     c  ON c.customer_id = rc.customer_id',
'LEFT JOIN sales_order so ON so.order_id = rc.order_id',
'WHERE  rc.return_case_id = :P3_RETURN_CASE_ID;'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
,p_query_row_template=>2538654340625403440
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_num_rows_type=>'NEXT_PREVIOUS_LINKS'
,p_pagination_display_position=>'BOTTOM_RIGHT'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
);
