,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight:t-Report--noBorders'
,p_display_point=>'SUB_REGIONS'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    soi.sku,',
'    soi.product_name,',
'    soi.qty,',
'    soi.unit_price,',
'    soi.qty * soi.unit_price                    AS line_total,',
'    CASE soi.returnable_flag WHEN ''Y'' THEN ''Yes'' ELSE ''No'' END AS returnable,',
'    CASE soi.delivered_flag  WHEN ''Y'' THEN ''Yes'' ELSE ''No'' END AS delivered,',
'    soi.return_window_days',
'FROM   sales_order_item soi',
'JOIN   return_case      rc  ON rc.order_id = soi.order_id',
'WHERE  rc.return_case_id = :P3_RETURN_CASE_ID',
'ORDER BY soi.order_item_id;'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
,p_query_row_template=>2538654340625403440
