'function refreshWaFeed() {',
'  apex.server.process(',
'    "GET_WA_FEED",',
'    { pageItems: "#P3_CUSTOMER_ID" },          // pushes the item to session state',
'    { dataType: "text",',
'      success: function (html) {',
'        apex.jQuery("#wa-feed-wrap").html(html);',
'        var f = document.getElementById("wa-feed");',
'        if (f) { f.scrollTop = f.scrollHeight; } // auto-scroll to newest',
'      }',
'    }',
'  );',
'}',
'',
'if (window.chatPoll) { clearInterval(window.chatPoll); }',
'window.chatPoll = setInterval(function () {',
'  if (document.hidden) { return; }',
'  if (!$v("P3_CUSTOMER_ID")) { return; }',
'  refreshWaFeed();',
'}, 3000);',
'',
'refreshWaFeed();   // paint once immediately, don''t wait 3s'))
);
