wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(16236851987524905)
,p_process_sequence=>60
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Approve Return'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_phone      customer.mobile_phone%TYPE;',
'    l_rma_number return_case.rma_number%TYPE;',
'    l_order_num  sales_order.order_number%TYPE;',
'BEGIN',
'    -- Get case details',
'    SELECT c.mobile_phone, rc.rma_number, so.order_number',
'    INTO   l_phone, l_rma_number, l_order_num',
'    FROM   return_case  rc',
'    JOIN   customer     c  ON c.customer_id = rc.customer_id',
'    LEFT JOIN sales_order so ON so.order_id = rc.order_id',
'    WHERE  rc.return_case_id = :P3_RETURN_CASE_ID;',
'',
'    -- Update case',
'    UPDATE return_case',
'    SET    case_status     = ''CLOSED'',',
'           approval_status = ''APPROVED'',',
'           updated_on      = SYSTIMESTAMP',
'    WHERE  return_case_id  = :P3_RETURN_CASE_ID;',
'',
'    -- Audit',
'    INSERT INTO workflow_event (',
'        correlation_id, related_entity_type, related_entity_id,',
'        event_type, event_source, outcome_status',
'    ) VALUES (',
'        ''APEX_APPROVE_'' || :P3_RETURN_CASE_ID,',
'        ''RETURN_CASE'', TO_NUMBER(:P3_RETURN_CASE_ID),',
'        ''RETURN_APPROVED'', ''APEX'', ''SUCCESS''',
'    );',
'',
'',
'    -- Notify customer via WhatsApp',
'    notification_api.send_whatsapp(',
'        p_to_phone => l_phone,',
'        p_message  => ''Good news! Your return request ''',
'                   || l_rma_number',
'                   || '' for order '' || l_order_num',
'                   || '' has been approved. ''',
'                   || ''We will email you a prepaid return label within 24 hours. ''',
'                   || ''Thank you for your patience!''',
'    );',
'',
'',
'    -- Show success message in APEX',
'    apex_application.g_print_success_message := ''Return ''',
'        || l_rma_number || '' approved and customer notified.'';',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        apex_error.add_error(',
'            p_message          => ''Approval failed: '' || SQLERRM,',
'            p_display_location => apex_error.c_inline_in_notification',
'        );',
'END;',
''))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(16236790819524904)
,p_internal_uid=>16236851987524905
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(16237092465524907)
,p_process_sequence=>70
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Reject Return'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    l_phone      customer.mobile_phone%TYPE;',
'    l_rma_number return_case.rma_number%TYPE;',
'    l_order_num  sales_order.order_number%TYPE;',
'BEGIN',
'    SELECT c.mobile_phone, rc.rma_number, so.order_number',
'    INTO   l_phone, l_rma_number, l_order_num',
'    FROM   return_case  rc',
'    JOIN   customer     c  ON c.customer_id = rc.customer_id',
'    LEFT JOIN sales_order so ON so.order_id = rc.order_id',
'    WHERE  rc.return_case_id = :P3_RETURN_CASE_ID;',
'',
'    UPDATE return_case',
'    SET    case_status     = ''CLOSED'',',
'           approval_status = ''REJECTED'',',
'           updated_on      = SYSTIMESTAMP',
'    WHERE  return_case_id  = :P3_RETURN_CASE_ID;',
'',
'    INSERT INTO workflow_event (',
'        correlation_id, related_entity_type, related_entity_id,',
'        event_type, event_source, outcome_status',
'    ) VALUES (',
'        ''APEX_REJECT_'' || :P3_RETURN_CASE_ID,',
'        ''RETURN_CASE'', TO_NUMBER(:P3_RETURN_CASE_ID),',
'        ''RETURN_REJECTED'', ''APEX'', ''SUCCESS''',
'    );',
'',
'',
'    notification_api.send_whatsapp(',
'        p_to_phone => l_phone,',
'        p_message  => ''Regarding your return request ''',
'                   || l_rma_number',
'                   || '' for order '' || l_order_num',
'                   || '': after review, we are unable to approve this return under our current policy. ''',
'                   || ''Please reply here or contact our support team if you have questions.''',
'    );',
'',
'',
'',
'    apex_application.g_print_success_message := ''Return ''',
'        || l_rma_number || '' rejected and customer notified.'';',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        apex_error.add_error(',
'            p_message          => ''Rejection failed: '' || SQLERRM,',
'            p_display_location => apex_error.c_inline_in_notification',
'        );',
'',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(16236906736524906)
,p_internal_uid=>16237092465524907
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(17243254054840331)
,p_process_sequence=>80
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Send WhatsApp'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'',
'l_conversation_id number;',
'',
'BEGIN',
'',
'BEGIN',
'',
'    select conversation_id ',
'    into l_conversation_id',
'    from conversation',
'    where customer_id=:P3_CUSTOMER_ID;',
' ',
' EXCEPTION',
'',
'    when others then',
'        l_conversation_id:=null;',
' END;',
'',
'',
'',
'  send_whatsapp_reply(',
'    p_conversation_id => l_conversation_id,',
'    p_message_text    => :P3_REPLY_TO_CUSTOMER',
'  );',
'',
'  -- Clear the textarea after send',
'  :P3_REPLY_TO_CUSTOMER := NULL;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(17243170431840330)
,p_required_patch=>wwv_flow_imp.id(16169697995688923)
,p_internal_uid=>17243254054840331
);
