wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(19170609413737206)
,p_process_sequence=>10
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'GET_WA_FEED'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  l_html  CLOB := '''';',
'  l_class VARCHAR2(20);',
'BEGIN',
'  l_html := ''<div class="wa-feed" id="wa-feed">'';',
'  FOR r IN (',
'    SELECT cm.direction, cm.message_text,',
'           TO_CHAR(cm.created_on,''HH24:MI'') AS msg_time',
'    FROM   conversation_message cm, conversation c',
'    WHERE  cm.conversation_id = c.conversation_id',
'    AND    c.customer_id = :P3_CUSTOMER_ID',
'    ORDER  BY cm.created_on ASC',
'  ) LOOP',
'    l_class := CASE r.direction WHEN ''INBOUND'' THEN ''wa-bubble-in''',
'                                ELSE ''wa-bubble-out'' END;',
'    l_html := l_html',
'      || ''<div class="wa-row"><div class="''||l_class||''">''',
'      || ''<div class="wa-text">''||APEX_ESCAPE.HTML(r.message_text)||''</div>''',
'      || ''<div class="wa-meta">''||r.msg_time||''</div>''',
'      || ''</div></div>'';',
'  END LOOP;',
'  l_html := l_html || ''</div>'';',
'  htp.p(l_html);',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>19170609413737206
);
end;
/
