prompt --application/deployment/install/install_01_schema
begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(19856111550175331)
,p_install_id=>wwv_flow_imp.id(19855223805156187)
,p_name=>'01_schema'
,p_sequence=>10
,p_script_type=>'INSTALL'
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'  CREATE TABLE "CONVERSATION" ',
'   (	"CONVERSATION_ID" NUMBER GENERATED ALWAYS AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL ENABLE, ',
'	"CHANNEL" VARCHAR2(30) DEFAULT ''WHATSAPP'', ',
'	"CUSTOMER_ID" NUMBER, ',
'	"CUSTOMER_PHONE" VARCHAR2(30), ',
'	"CURRENT_STATE" VARCHAR2(50) DEFAULT ''NEW'', ',
'	"CURRENT_STEP" VARCHAR2(100), ',
'	"PENDING_QUESTION" VARCHAR2(500), ',
'	"OPEN_RETURN_CASE_ID" NUMBER, ',
'	"LAST_MESSAGE_AT" TIMESTAMP (6), ',
'	"STATUS" VARCHAR2(20) DEFAULT ''ACTIVE'', ',
'	"CREATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	"UPDATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	"CONTEXT" CLOB, ',
'	 PRIMARY KEY ("CONVERSATION_ID")',
'  USING INDEX  ENABLE, ',
'	 CONSTRAINT "CONTEXT_IS_JSON" CHECK (context IS JSON) ENABLE',
'   ) ;',
'',
'  CREATE TABLE "CONVERSATION_MESSAGE" ',
'   (	"MESSAGE_ID" NUMBER GENERATED ALWAYS AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL ENABLE, ',
'	"CONVERSATION_ID" NUMBER NOT NULL ENABLE, ',
'	"DIRECTION" VARCHAR2(10) NOT NULL ENABLE, ',
'	"PROVIDER_MESSAGE_ID" VARCHAR2(100), ',
'	"MESSAGE_TEXT" CLOB, ',
'	"MEDIA_FLAG" VARCHAR2(1) DEFAULT ''N'', ',
'	"MEDIA_URL" VARCHAR2(1000), ',
'	"RAW_PAYLOAD_JSON" CLOB, ',
'	"DELIVERY_STATUS" VARCHAR2(30), ',
'	"CREATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	 CONSTRAINT "CONV_MSG_DIR_CK" CHECK (direction IN (''INBOUND'',''OUTBOUND'')) ENABLE, ',
'	 PRIMARY KEY ("MESSAGE_ID")',
'  USING INDEX  ENABLE',
'   ) ;',
'',
'  CREATE TABLE "WORKFLOW_EVENT" ',
'   (	"WORKFLOW_EVENT_ID" NUMBER GENERATED ALWAYS AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL ENABLE, ',
'	"CORRELATION_ID" VARCHAR2(200), ',
'	"RELATED_ENTITY_TYPE" VARCHAR2(50), ',
'	"RELATED_ENTITY_ID" NUMBER, ',
'	"EVENT_TYPE" VARCHAR2(100), ',
'	"EVENT_SOURCE" VARCHAR2(50), ',
'	"REQUEST_PAYLOAD" CLOB, ',
'	"RESPONSE_PAYLOAD" CLOB, ',
'	"OUTCOME_STATUS" VARCHAR2(20), ',
'	"ERROR_MESSAGE" VARCHAR2(2000), ',
'	"CREATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	 PRIMARY KEY ("WORKFLOW_EVENT_ID")',
'  USING INDEX  ENABLE',
'   ) ;',
'',
'  CREATE TABLE "APP_CONFIG" ',
'   (	"CONFIG_KEY" VARCHAR2(100) NOT NULL ENABLE, ',
'	"CONFIG_VALUE" VARCHAR2(1000), ',
'	"DESCRIPTION" VARCHAR2(500), ',
'	"UPDATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP, ',
'	 PRIMARY KEY ("CONFIG_KEY")',
'  USING INDEX  ENABLE',
'   ) ;',
'',
'  CREATE TABLE "CUSTOMER" ',
'   (	"CUSTOMER_ID" NUMBER GENERATED ALWAYS AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL ENABLE, ',
'	"CUSTOMER_NUMBER" VARCHAR2(20) NOT NULL ENABLE, ',
'	"FIRST_NAME" VARCHAR2(100), ',
'	"LAST_NAME" VARCHAR2(100), ',
'	"EMAIL" VARCHAR2(255), ',
'	"MOBILE_PHONE" VARCHAR2(30), ',
'	"PREFERRED_LANGUAGE" VARCHAR2(10) DEFAULT ''en'', ',
'	"STATUS" VARCHAR2(20) DEFAULT ''ACTIVE'', ',
'	"CREATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	"UPDATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	 CONSTRAINT "CUSTOMER_STATUS_CK" CHECK (status IN (''ACTIVE'',''INACTIVE'',''BLOCKED'')) ENABLE, ',
'	 PRIMARY KEY ("CUSTOMER_ID")',
'  USING INDEX  ENABLE',
'   ) ;',
'',
'  CREATE TABLE "CUSTOMER_ADDRESS" ',
'   (	"ADDRESS_ID" NUMBER GENERATED ALWAYS AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL ENABLE, ',
'	"CUSTOMER_ID" NUMBER NOT NULL ENABLE, ',
'	"ADDRESS_TYPE" VARCHAR2(20) DEFAULT ''SHIPPING'', ',
'	"ADDRESS_LINE1" VARCHAR2(200), ',
'	"ADDRESS_LINE2" VARCHAR2(200), ',
'	"CITY" VARCHAR2(100), ',
'	"REGION" VARCHAR2(100), ',
'	"POSTAL_CODE" VARCHAR2(20), ',
'	"COUNTRY_CODE" VARCHAR2(3) DEFAULT ''CA'', ',
'	"IS_DEFAULT" VARCHAR2(1) DEFAULT ''Y'', ',
'	"CREATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	 CONSTRAINT "ADDR_TYPE_CK" CHECK (address_type IN (''SHIPPING'',''BILLING'')) ENABLE, ',
'	 PRIMARY KEY ("ADDRESS_ID")',
'  USING INDEX  ENABLE',
'   ) ;',
'',
'  CREATE TABLE "RETURN_CASE" ',
'   (	"RETURN_CASE_ID" NUMBER GENERATED ALWAYS AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL ENABLE, ',
'	"RMA_NUMBER" VARCHAR2(30), ',
'	"CUSTOMER_ID" NUMBER NOT NULL ENABLE, ',
'	"ORDER_ID" NUMBER, ',
'	"CHANNEL" VARCHAR2(30) DEFAULT ''WHATSAPP'', ',
'	"CASE_STATUS" VARCHAR2(30) DEFAULT ''OPEN'', ',
'	"REASON_CODE" VARCHAR2(50), ',
'	"CUSTOMER_DESCRIPTION" VARCHAR2(2000), ',
'	"REQUESTED_RESOLUTION" VARCHAR2(30), ',
'	"FINAL_RESOLUTION" VARCHAR2(30), ',
'	"APPROVAL_REQUIRED_FLAG" VARCHAR2(1) DEFAULT ''N'', ',
'	"APPROVAL_STATUS" VARCHAR2(20), ',
'	"CONVERSATION_ID" NUMBER, ',
'	"CORRELATION_ID" VARCHAR2(200), ',
'	"IDEMPOTENCY_KEY" VARCHAR2(300), ',
'	"CREATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	"UPDATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	"CREATED_BY_SOURCE" VARCHAR2(50) DEFAULT ''WHATSAPP_BOT'', ',
'	 CONSTRAINT "RC_STATUS_CK" CHECK (case_status IN (',
'                                    ''OPEN'',''PENDING_EVIDENCE'',''PENDING_APPROVAL'',',
'                                    ''APPROVED'',''REJECTED'',''FULFILLED'',''CLOSED'')) ENABLE, ',
'	 PRIMARY KEY ("RETURN_CASE_ID")',
'  USING INDEX  ENABLE',
'   ) ;',
'',
'  CREATE TABLE "SALES_ORDER" ',
'   (	"ORDER_ID" NUMBER GENERATED ALWAYS AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL ENABLE, ',
'	"ORDER_NUMBER" VARCHAR2(30) NOT NULL ENABLE, ',
'	"CUSTOMER_ID" NUMBER NOT NULL ENABLE, ',
'	"ORDER_DATE" DATE, ',
'	"DELIVERY_DATE" DATE, ',
'	"ORDER_STATUS" VARCHAR2(30) DEFAULT ''DELIVERED'', ',
'	"PAYMENT_STATUS" VARCHAR2(30) DEFAULT ''PAID'', ',
'	"CURRENCY" VARCHAR2(3) DEFAULT ''CAD'', ',
'	"ORDER_TOTAL" NUMBER(10,2), ',
'	"SOURCE_CHANNEL" VARCHAR2(30) DEFAULT ''WEB'', ',
'	"CREATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	"UPDATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	 CONSTRAINT "ORDER_STATUS_CK" CHECK (order_status IN (',
'                            ''PENDING'',''PROCESSING'',''SHIPPED'',',
'                            ''DELIVERED'',''CANCELLED'',''RETURNED'')) ENABLE, ',
'	 PRIMARY KEY ("ORDER_ID")',
'  USING INDEX  ENABLE',
'   ) ;',
'',
'  CREATE TABLE "SALES_ORDER_ITEM" ',
'   (	"ORDER_ITEM_ID" NUMBER GENERATED ALWAYS AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL ENABLE, ',
'	"ORDER_ID" NUMBER NOT NULL ENABLE, ',
'	"SKU" VARCHAR2(50) NOT NULL ENABLE, ',
'	"PRODUCT_NAME" VARCHAR2(200), ',
'	"QTY" NUMBER DEFAULT 1, ',
'	"UNIT_PRICE" NUMBER(10,2), ',
'	"RETURNABLE_FLAG" VARCHAR2(1) DEFAULT ''Y'', ',
'	"WARRANTY_FLAG" VARCHAR2(1) DEFAULT ''N'', ',
'	"DELIVERED_FLAG" VARCHAR2(1) DEFAULT ''Y'', ',
'	"RETURN_WINDOW_DAYS" NUMBER DEFAULT 30, ',
'	"CREATED_ON" TIMESTAMP (6) DEFAULT SYSTIMESTAMP NOT NULL ENABLE, ',
'	 PRIMARY KEY ("ORDER_ITEM_ID")',
'  USING INDEX  ENABLE',
'   ) ;',
'',
'  ALTER TABLE "CONVERSATION" ADD FOREIGN KEY ("CUSTOMER_ID")',
'	  REFERENCES "CUSTOMER" ("CUSTOMER_ID") ENABLE;',
'  ALTER TABLE "CONVERSATION" ADD FOREIGN KEY ("OPEN_RETURN_CASE_ID")',
'	  REFERENCES "RETURN_CASE" ("RETURN_CASE_ID") ENABLE;',
'',
'  CREATE INDEX "CONVERSATION_CUST_IDX" ON "CONVERSATION" ("CUSTOMER_ID") ',
'  ;',
'',
'  CREATE INDEX "CONVERSATION_PHONE_IDX" ON "CONVERSATION" ("CUSTOMER_PHONE") ',
'  ;',
'',
'  CREATE OR REPLACE EDITIONABLE TRIGGER "CONVERSATION_BUR" ',
'    BEFORE UPDATE ON conversation',
'    FOR EACH ROW',
'BEGIN',
'    :new.updated_on := SYSTIMESTAMP;',
'END;',
'/',
'ALTER TRIGGER "CONVERSATION_BUR" ENABLE;',
