'	  REFERENCES "CONVERSATION" ("CONVERSATION_ID") ENABLE;',
'',
'  CREATE INDEX "CONV_MSG_CONV_IDX" ON "CONVERSATION_MESSAGE" ("CONVERSATION_ID") ',
'  ;',
'',
'  CREATE UNIQUE INDEX "CONV_MSG_PROVIDER_UI" ON "CONVERSATION_MESSAGE" ("PROVIDER_MESSAGE_ID") ',
'  ;',
'',
'  CREATE INDEX "CUSTOMER_EMAIL_IDX" ON "CUSTOMER" ("EMAIL") ',
'  ;',
'',
'  CREATE UNIQUE INDEX "CUSTOMER_NUMBER_UI" ON "CUSTOMER" ("CUSTOMER_NUMBER") ',
'  ;',
'',
'  CREATE UNIQUE INDEX "CUSTOMER_PHONE_UI" ON "CUSTOMER" ("MOBILE_PHONE") ',
'  ;',
'',
'  ALTER TABLE "CUSTOMER_ADDRESS" ADD FOREIGN KEY ("CUSTOMER_ID")',
'	  REFERENCES "CUSTOMER" ("CUSTOMER_ID") ENABLE;',
'',
'  CREATE INDEX "CUST_ADDR_CUST_IDX" ON "CUSTOMER_ADDRESS" ("CUSTOMER_ID") ',
'  ;',
'',
'  ALTER TABLE "RETURN_CASE" ADD FOREIGN KEY ("CUSTOMER_ID")',
'	  REFERENCES "CUSTOMER" ("CUSTOMER_ID") ENABLE;',
'  ALTER TABLE "RETURN_CASE" ADD FOREIGN KEY ("ORDER_ID")',
'	  REFERENCES "SALES_ORDER" ("ORDER_ID") ENABLE;',
'',
'  CREATE INDEX "RC_CUSTOMER_IDX" ON "RETURN_CASE" ("CUSTOMER_ID") ',
'  ;',
'',
'  CREATE UNIQUE INDEX "RC_IDEMPOTENCY_UI" ON "RETURN_CASE" ("IDEMPOTENCY_KEY") ',
'  ;',
'',
'  CREATE INDEX "RC_ORDER_IDX" ON "RETURN_CASE" ("ORDER_ID") ',
'  ;',
'',
'  CREATE UNIQUE INDEX "RC_RMA_UI" ON "RETURN_CASE" ("RMA_NUMBER") ',
'  ;',
'',
'  CREATE OR REPLACE EDITIONABLE TRIGGER "RETURN_CASE_BIR" ',
'    BEFORE INSERT ON return_case',
'    FOR EACH ROW',
'BEGIN',
'    IF :new.rma_number IS NULL THEN',
'        :new.rma_number := ''RMA-'' || TO_CHAR(rma_number_seq.NEXTVAL);',
'    END IF;',
'    :new.updated_on := SYSTIMESTAMP;',
'END;',
'/',
'ALTER TRIGGER "RETURN_CASE_BIR" ENABLE;',
'  CREATE OR REPLACE EDITIONABLE TRIGGER "RETURN_CASE_BUR" ',
'    BEFORE UPDATE ON return_case',
'    FOR EACH ROW',
'BEGIN',
'    :new.updated_on := SYSTIMESTAMP;',
'END;',
'/',
'ALTER TRIGGER "RETURN_CASE_BUR" ENABLE;',
'',
'  ALTER TABLE "SALES_ORDER" ADD FOREIGN KEY ("CUSTOMER_ID")',
'	  REFERENCES "CUSTOMER" ("CUSTOMER_ID") ENABLE;',
'',
'  CREATE INDEX "SALES_ORDER_CUST_IDX" ON "SALES_ORDER" ("CUSTOMER_ID") ',
'  ;',
'',
'  CREATE UNIQUE INDEX "SALES_ORDER_NUMBER_UI" ON "SALES_ORDER" ("ORDER_NUMBER") ',
'  ;',
'',
'  ALTER TABLE "SALES_ORDER_ITEM" ADD FOREIGN KEY ("ORDER_ID")',
'	  REFERENCES "SALES_ORDER" ("ORDER_ID") ENABLE;',
'',
'  CREATE INDEX "ORDER_ITEM_ORDER_IDX" ON "SALES_ORDER_ITEM" ("ORDER_ID") ',
'  ;',
'',
'  CREATE INDEX "WE_CORRELATION_IDX" ON "WORKFLOW_EVENT" ("CORRELATION_ID") ',
'  ;',
'',
'  CREATE INDEX "WE_CREATED_IDX" ON "WORKFLOW_EVENT" ("CREATED_ON") ',
'  ;',
'',
'  CREATE INDEX "WE_ENTITY_IDX" ON "WORKFLOW_EVENT" ("RELATED_ENTITY_TYPE", "RELATED_ENTITY_ID") ',
'  ;',
'',
'',
'',
'',
'',
'',
'',
'',
'',
'create or replace FUNCTION get_sparkline_data(p_status_filter VARCHAR2)',
'RETURN VARCHAR2 IS',
'    l_result VARCHAR2(200);',
'BEGIN',
'    SELECT LISTAGG(cnt, '','') WITHIN GROUP (ORDER BY d)',
'    INTO   l_result',
'    FROM (',
'        SELECT dates.d, COUNT(rc.return_case_id) AS cnt',
'        FROM (',
'            SELECT TRUNC(SYSDATE) - (7 - LEVEL) AS d',
'            FROM dual CONNECT BY LEVEL <= 7',
'        ) dates',
'        LEFT JOIN return_case rc',
'            ON  TRUNC(rc.created_on) = dates.d',
'            AND rc.case_status IN (p_status_filter)',
'        GROUP BY dates.d',
'    );',
'    RETURN l_result;',
'END;',
'/ '))
);
