prompt --application/deployment/install/install_02_package
begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(19858020986178365)
,p_install_id=>wwv_flow_imp.id(19855223805156187)
,p_name=>'02_package'
,p_sequence=>20
,p_script_type=>'INSTALL'
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'create or replace PACKAGE notification_api AS ',
' ',
'    -- Send a WhatsApp message to a customer phone number. ',
'    -- p_to_phone: E.164 digits only, no + (e.g. 15149796975) ',
'    -- p_message:  plain text, max ~1600 chars for WhatsApp ',
'    PROCEDURE send_whatsapp ( ',
'        p_to_phone  IN VARCHAR2, ',
'        p_message   IN VARCHAR2 ',
'    ); ',
' ',
'END notification_api;',
'/',
'create or replace PACKAGE BODY notification_api AS',
'',
'    PROCEDURE send_whatsapp (',
'        p_to_phone  IN VARCHAR2,',
'        p_message   IN VARCHAR2',
'    ) IS',
'        l_account_sid   VARCHAR2(100);',
'        l_auth_token    VARCHAR2(100);',
'        l_from_number   VARCHAR2(30);',
'        l_url           VARCHAR2(500);',
'        l_body          VARCHAR2(4000);',
'        l_response      CLOB;',
'        l_status_code   NUMBER;',
'        -- Resolved before INSERT to avoid CASE/functions in VALUES clause',
'        l_outcome       VARCHAR2(20);',
'        l_error_msg     VARCHAR2(2000);',
'        l_corr_id       VARCHAR2(100);',
'        l_request_log   VARCHAR2(4000);',
'        l_conversation_id NUMBER;',
'    BEGIN',
'        -- Load credentials from config table',
'        SELECT config_value INTO l_account_sid',
'        FROM   app_config WHERE config_key = ''TWILIO_ACCOUNT_SID'';',
'',
'        SELECT config_value INTO l_auth_token',
'        FROM   app_config WHERE config_key = ''TWILIO_AUTH_TOKEN'';',
'',
'        SELECT config_value INTO l_from_number',
'        FROM   app_config WHERE config_key = ''TWILIO_FROM_WHATSAPP'';',
'',
'        l_url := ''https://api.twilio.com/2010-04-01/Accounts/''',
'                 || l_account_sid || ''/Messages.json'';',
'',
'        -- Build form-encoded body.',
unistr('        -- The + in whatsapp:+<number> must be encoded as %2B \2014 in form encoding,'),
'        -- a raw + decodes as a space, which Twilio rejects with error 21211.',
'        -- l_from_number is stored with a leading + (e.g. +14155238886); strip it.',
'        l_body := ''To=whatsapp%3A%2B''    || p_to_phone',
'               || ''&From=whatsapp%3A%2B'' || LTRIM(l_from_number, ''+'')',
'               || ''&Body=''               || UTL_URL.ESCAPE(p_message, FALSE);',
'',
'        -- Set Content-Type header',
'        apex_web_service.g_request_headers(1).name  := ''Content-Type'';',
'        apex_web_service.g_request_headers(1).value := ''application/x-www-form-urlencoded'';',
'',
'        -- Make the call',
'        l_response := apex_web_service.make_rest_request(',
'            p_url         => l_url,',
'            p_http_method => ''POST'',',
'            p_username    => l_account_sid,',
'            p_password    => l_auth_token,',
'            p_body        => l_body',
'        );',
'',
'        l_status_code := apex_web_service.g_status_code;',
'',
'        -- Resolve all values into variables before INSERT',
'        l_corr_id     := ''APEX_NOTIFY_'' || TO_CHAR(SYSTIMESTAMP, ''YYYYMMDDHH24MISSFF3'');',
'        l_request_log := SUBSTR(''To: +'' || p_to_phone || '' | Msg: '' || p_message, 1, 4000);',
'',
'        IF l_status_code BETWEEN 200 AND 299 THEN',
'            l_outcome   := ''SUCCESS'';',
'            l_error_msg := NULL;',
'        ELSE',
'            l_outcome   := ''FAILURE'';',
'            l_error_msg := ''HTTP '' || TO_CHAR(l_status_code) || '': ''',
'                           || SUBSTR(l_response, 1, 500);',
'        END IF;',
'',
unistr('        -- Log outcome \2014 only plain variables in the VALUES clause'),
'        INSERT INTO workflow_event (',
'            correlation_id,',
'            related_entity_type,',
'            event_type,',
'            event_source,',
'            request_payload,',
'            response_payload,',
'            outcome_status,',
'            error_message',
'        ) VALUES (',
'            l_corr_id,',
'            ''NOTIFICATION'',',
'            ''WHATSAPP_SENT'',',
'            ''APEX'',',
'            l_request_log,',
'            SUBSTR(l_response, 1, 4000),',
'            l_outcome,',
'            l_error_msg',
'        );',
'',
'',
'select conversation_id into l_conversation_id',
'from conversation',
'where customer_phone=p_to_phone;',
'',
'',
'        INSERT INTO conversation_message (',
'    conversation_id, direction, message_text, created_on',
'  ) VALUES (',
'    l_conversation_id, ''OUTBOUND'', p_message,',
'      SYSTIMESTAMP',
'  );',
'',
'  UPDATE conversation',
'  SET    last_message_at = SYSTIMESTAMP',
'  WHERE  conversation_id = l_conversation_id;',
'',
'',
'    EXCEPTION',
'        WHEN OTHERS THEN',
'            DECLARE',
'                l_err VARCHAR2(2000) := SUBSTR(SQLERRM, 1, 2000);',
'            BEGIN',
'                INSERT INTO workflow_event (',
'                    correlation_id, related_entity_type, event_type,',
'                    event_source, outcome_status, error_message',
'                ) VALUES (',
'                    ''APEX_NOTIFY_ERROR'',',
'                    ''NOTIFICATION'', ''WHATSAPP_SEND_FAILED'',',
'                    ''APEX'', ''FAILURE'', l_err',
'                );',
'            END;',
'    END send_whatsapp;',
'',
'END notification_api;',
'/ '))
);
wwv_flow_imp_shared.create_install_object(
 p_id=>wwv_flow_imp.id(19858119677178365)
,p_script_id=>wwv_flow_imp.id(19858020986178365)
,p_object_owner=>'#OWNER#'
,p_object_type=>'PACKAGE'
,p_object_name=>'NOTIFICATION_API'
);
end;
/
prompt --application/deployment/install/install_seed_data
begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(19898498571685518)
,p_install_id=>wwv_flow_imp.id(19855223805156187)
,p_name=>'seed data'
,p_sequence=>30
,p_script_type=>'INSTALL'
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- =============================================================',
'-- Kscope26: When APEX Talks Back',
'-- Script 02: Demo Seed Data',
'-- Run AFTER 01_schema_ddl.sql',
'-- Run in: APEX SQL Workshop > SQL Scripts',
'-- =============================================================',
'',
'-- Clear existing demo data (safe re-run)',
'DELETE FROM workflow_event;',
'DELETE FROM conversation_message;',
'DELETE FROM conversation;',
'DELETE FROM return_case;',
'DELETE FROM sales_order_item;',
'DELETE FROM sales_order;',
'DELETE FROM customer_address;',
'DELETE FROM customer;',
'COMMIT;',
'',
'-- =============================================================',
'-- CUSTOMERS',
'-- =============================================================',
unistr('-- CUST-001: Michelle \2014 your own WhatsApp number for live testing'),
'INSERT INTO customer (',
'    customer_number, first_name, last_name,',
'    email, mobile_phone, preferred_language, status',
') VALUES (',
'    ''CUST-001'', ''Michael'', ''Smith'',',
'    ''michelle@example.com'', ''15145551212'', ''en'', ''ACTIVE''',
');',
'',
unistr('-- CUST-002: Jean \2014 French-language customer, for multilingual demo'),
'INSERT INTO customer (',
'    customer_number, first_name, last_name,',
'    email, mobile_phone, preferred_language, status',
') VALUES (',
'    ''CUST-002'', ''Jean'', ''Tremblay'',',
'    ''jean.tremblay@example.com'', ''15141230001'', ''fr'', ''ACTIVE''',
');',
'',
unistr('-- CUST-003: Sarah \2014 high-value order scenario'),
'INSERT INTO customer (',
