/
prompt --application/deployment/install/install_rest_endpoints
begin
wwv_flow_imp_shared.create_install_script(
 p_id=>wwv_flow_imp.id(19898637377693667)
,p_install_id=>wwv_flow_imp.id(19855223805156187)
,p_name=>'REST Endpoints'
,p_sequence=>40
,p_script_type=>'INSTALL'
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- =============================================================',
'-- Kscope26: When APEX Talks Back',
'-- Script 03: ORDS REST API Setup',
'-- Run AFTER 01_schema_ddl.sql and 02_seed_data.sql',
'-- Run in: APEX SQL Workshop > SQL Scripts',
'--',
'-- Base URL pattern will be:',
'--   https://<your-apex-host>/ords/<schema>/api/...',
'',
'-- =============================================================',
'',
'-- =============================================================',
'-- Drop and recreate the module (safe re-run)',
'-- =============================================================',
'',
'-- =============================================================',
'-- Define the module',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_MODULE(',
'        p_module_name    => ''rma_api'',',
'        p_base_path      => ''/api/'',',
'        p_items_per_page => 25,',
'        p_status         => ''PUBLISHED'',',
'        p_comments       => ''RMA Copilot REST API for n8n integration''',
'    );',
'',
'END;',
'/',
'',
'-- =============================================================',
'-- ENDPOINT 1: GET /api/customers/by-phone/:phone',
'--',
'-- Used by n8n Workflow A to identify the customer after',
'-- receiving a WhatsApp message.',
'--',
'-- Success:  { "found": true,  "customer_id": 1, "customer_number": "CUST-001", ... }',
'-- Not found:{ "found": false, "mobile_phone": "15149796975" }',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_TEMPLATE(',
'        p_module_name => ''rma_api'',',
'        p_pattern     => ''customers/by-phone/:phone''',
'    );',
'',
'    ORDS.DEFINE_HANDLER(',
'        p_module_name   => ''rma_api'',',
'        p_pattern       => ''customers/by-phone/:phone'',',
'        p_method        => ''GET'',',
'        p_source_type   => ORDS.SOURCE_TYPE_PLSQL,',
'        p_comments      => ''Identify customer by WhatsApp phone number (E.164 digits, no +)'',',
'        p_source        => q''[',
'DECLARE',
'    l_customer_id   customer.customer_id%TYPE;',
'    l_cnum          customer.customer_number%TYPE;',
'    l_first         customer.first_name%TYPE;',
'    l_last          customer.last_name%TYPE;',
'    l_email         customer.email%TYPE;',
'    l_lang          customer.preferred_language%TYPE;',
'    l_status        customer.status%TYPE;',
'BEGIN',
'    SELECT customer_id, customer_number, first_name, last_name,',
'           email, preferred_language, status',
'    INTO   l_customer_id, l_cnum, l_first, l_last,',
'           l_email, l_lang, l_status',
'    FROM   customer',
'    WHERE  mobile_phone = :phone',
'    AND    status       = ''ACTIVE'';',
'',
'    OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'    HTP.PRN(JSON_OBJECT(',
'        ''found''           VALUE ''true''   FORMAT JSON,',
'        ''customer_id''     VALUE l_customer_id,',
'        ''customer_number'' VALUE l_cnum,',
'        ''first_name''      VALUE l_first,',
'        ''last_name''       VALUE l_last,',
'        ''email''           VALUE l_email,',
'        ''mobile_phone''    VALUE :phone,',
'        ''preferred_language'' VALUE l_lang,',
'        ''status''          VALUE l_status',
'    ));',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        :status_code := 404;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(',
'            ''found''        VALUE ''false'' FORMAT JSON,',
'            ''mobile_phone'' VALUE :phone',
'        ));',
'END;',
'        ',
'        ]''',
'    );',
'',
'END;',
'/',
'',
'-- =============================================================',
'-- ENDPOINT 2: GET /api/orders/:order_number',
'--',
'-- Returns order header + all items for a given order number.',
'-- n8n calls this to retrieve order context after identification.',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_TEMPLATE(',
'        p_module_name => ''rma_api'',',
'        p_pattern     => ''orders/:order_number''',
'    );',
'',
'    ORDS.DEFINE_HANDLER(',
'        p_module_name   => ''rma_api'',',
'        p_pattern       => ''orders/:order_number'',',
'        p_method        => ''GET'',',
'        p_source_type   => ORDS.SOURCE_TYPE_PLSQL,',
'        p_comments      => ''Get order header and line items by order number'',',
'        p_source        => q''{',
'DECLARE',
'    l_order_id      sales_order.order_id%TYPE;',
'    l_customer_id   sales_order.customer_id%TYPE;',
'    l_order_date    sales_order.order_date%TYPE;',
'    l_delivery_date sales_order.delivery_date%TYPE;',
'    l_status        sales_order.order_status%TYPE;',
'    l_currency      sales_order.currency%TYPE;',
'    l_total         sales_order.order_total%TYPE;',
'    l_items         CLOB;',
'BEGIN',
'    SELECT order_id, customer_id, order_date, delivery_date,',
'           order_status, currency, order_total',
'    INTO   l_order_id, l_customer_id, l_order_date, l_delivery_date,',
'           l_status, l_currency, l_total',
'    FROM   sales_order',
'    WHERE  order_number = :order_number;',
'',
'    -- Build items array',
'    SELECT JSON_ARRAYAGG(',
'               JSON_OBJECT(',
'                   ''order_item_id''     VALUE order_item_id,',
'                   ''sku''               VALUE sku,',
'                   ''product_name''      VALUE product_name,',
'                   ''qty''               VALUE qty,',
'                   ''unit_price''        VALUE unit_price,',
'                   ''returnable_flag''   VALUE returnable_flag,',
'                   ''delivered_flag''    VALUE delivered_flag,',
'                   ''return_window_days'' VALUE return_window_days',
'               )',
'               ORDER BY order_item_id',
'           )',
'    INTO l_items',
'    FROM sales_order_item',
'    WHERE order_id = l_order_id;',
'',
'    OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'    HTP.PRN(JSON_OBJECT(',
'        ''found''          VALUE ''true'' FORMAT JSON,',
'        ''order_id''       VALUE l_order_id,',
'        ''order_number''   VALUE :order_number,',
'        ''customer_id''    VALUE l_customer_id,',
'        ''order_date''     VALUE TO_CHAR(l_order_date, ''YYYY-MM-DD''),',
'        ''delivery_date''  VALUE TO_CHAR(l_delivery_date, ''YYYY-MM-DD''),',
'        ''order_status''   VALUE l_status,',
'        ''currency''       VALUE l_currency,',
'        ''order_total''    VALUE l_total,',
'        ''items''          VALUE NVL(l_items, ''[]'') FORMAT JSON',
'    ));',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        :status_code := 404;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(',
'            ''found''        VALUE ''false'' FORMAT JSON,',
'            ''order_number'' VALUE :order_number',
'        ));',
'END;',
'        ',
'        ',
'        }''',
'    );',
'',
'END;',
'/',
'',
'-- =============================================================',
'-- ENDPOINT 3: GET /api/orders/:order_number/return-eligibility',
'--',
'-- The key eligibility check. All business rules live here in',
unistr('-- the database \2014 NOT in n8n and NOT in the AI.'),
'--',
'-- Returns: { "eligible": true/false, "reason": "...",',
'--            "requires_approval": true/false,',
'--            "approval_threshold": 500, "items": [...] }',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_TEMPLATE(',
'        p_module_name => ''rma_api'',',
'        p_pattern     => ''orders/:order_number/return-eligibility''',
'    );',
'',
'    ORDS.DEFINE_HANDLER(',
'        p_module_name   => ''rma_api'',',
'        p_pattern       => ''orders/:order_number/return-eligibility'',',
'        p_method        => ''GET'',',
'        p_source_type   => ORDS.SOURCE_TYPE_PLSQL,',
'        p_comments      => ''Evaluate return eligibility for an order. Pass customer_id as query param to validate ownership.'',',
'        p_source        => q''{',
'DECLARE',
'',
'    l_approval_threshold  NUMBER;   -- CAD: orders above this need approval',
'',
'    l_order_id        sales_order.order_id%TYPE;',
'    l_customer_id     sales_order.customer_id%TYPE;',
'    l_delivery_date   sales_order.delivery_date%TYPE;',
'    l_order_total     sales_order.order_total%TYPE;',
'    l_order_status    sales_order.order_status%TYPE;',
'',
'    l_eligible        VARCHAR2(5);',
'    l_reason          VARCHAR2(200);',
'    l_req_approval    VARCHAR2(5) := ''false'';',
'    l_days_since      NUMBER;',
'    l_items           CLOB;',
'    l_existing_rma    NUMBER;',
'    l_norm            VARCHAR2(100);',
'BEGIN',
'',
'select to_number(config_value) into l_approval_threshold_cad',
'where CONFIG_KEY=''APPROVAL_THRESHOLD_CAD'';',
'',
'l_norm := UPPER(TRIM(:order_number));',
'IF REGEXP_LIKE(l_norm, ''^[0-9]+$'') THEN',
'  l_norm := ''ORD-'' || l_norm;     -- bare digits -> canonical form',
'END IF;',
'-- then match case-insensitively:',
'--   WHERE UPPER(order_number) = l_norm',
'    -- Fetch order',
'    SELECT order_id, customer_id, delivery_date,',
'           order_total, order_status',
'    INTO   l_order_id, l_customer_id, l_delivery_date,',
'           l_order_total, l_order_status',
'    FROM   sales_order',
'    WHERE  order_number = l_norm;',
'',
'    -- Rule 1: Customer must own the order',
'    IF :customer_id IS NOT NULL',
'       AND TO_NUMBER(:customer_id) != l_customer_id THEN',
'        l_eligible := ''false'';',
'        l_reason   := ''Order does not belong to this customer'';',
'        GOTO output;',
'    END IF;',
'',
'    -- Rule 2: Order must be delivered',
'    IF l_order_status != ''DELIVERED'' OR l_delivery_date IS NULL THEN',
'        l_eligible := ''false'';',
'        l_reason   := ''Order has not been delivered yet'';',
'        GOTO output;',
'    END IF;',
'',
'    -- Rule 3: Within return window (use shortest window across items)',
'    SELECT SYSDATE - l_delivery_date INTO l_days_since FROM DUAL;',
'',
'    DECLARE',
'        l_min_window NUMBER;',
'    BEGIN',
'        SELECT MIN(return_window_days)',
'        INTO   l_min_window',
'        FROM   sales_order_item',
'        WHERE  order_id = l_order_id;',
'',
'        IF l_days_since > l_min_window THEN',
'            l_eligible := ''false'';',
'            l_reason   := ''Return window of '' || l_min_window',
'                          || '' days has passed (''',
'                          || ROUND(l_days_since) || '' days since delivery)'';',
'            GOTO output;',
'        END IF;',
'    END;',
'',
'    -- Rule 4: No open RMA already exists for this order',
'    SELECT COUNT(*)',
'    INTO   l_existing_rma',
'    FROM   return_case',
'    WHERE  order_id    = l_order_id;',
'',
'    IF l_existing_rma > 0 THEN',
'        l_eligible := ''false'';',
'        l_reason   := ''An open return case already exists for this order'';',
'        GOTO output;',
'    END IF;',
'',
' ',
'',
'    -- All rules passed',
'    l_eligible := ''true'';',
'    l_reason   := ''Eligible for return'';',
'',
'    -- Check if high-value approval is required',
'    IF l_order_total >= c_approval_threshold THEN',
'        l_req_approval := ''true'';',
'    END IF;',
'',
'    <<output>>',
'    -- Build eligible items list',
'    SELECT JSON_ARRAYAGG(',
'               JSON_OBJECT(',
'                   ''order_item_id''   VALUE order_item_id,',
'                   ''sku''             VALUE sku,',
'                   ''product_name''    VALUE product_name,',
'                   ''qty''             VALUE qty,',
'                   ''unit_price''      VALUE unit_price,',
'                   ''eligible_for_return'' VALUE',
'                       CASE WHEN returnable_flag = ''Y''',
'                                 AND delivered_flag = ''Y''',
'                            THEN ''true'' ELSE ''false'' END FORMAT JSON',
'               )',
'               ORDER BY order_item_id',
'           )',
'    INTO l_items',
'    FROM sales_order_item',
'    WHERE order_id = l_order_id;',
'',
'    OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'    HTP.PRN(JSON_OBJECT(',
'        ''order_number''       VALUE :order_number,',
'        ''order_id''           VALUE l_order_id,',
'        ''eligible''           VALUE l_eligible           FORMAT JSON,',
'        ''reason''             VALUE l_reason,',
'        ''requires_approval''  VALUE l_req_approval       FORMAT JSON,',
'        ''approval_threshold'' VALUE c_approval_threshold,',
'        ''order_total''        VALUE l_order_total,',
'        ''days_since_delivery'' VALUE ROUND(l_days_since),',
'        ''items''              VALUE NVL(l_items, ''[]'')   FORMAT JSON',
'    ));',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'        :status_code := 404;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(',
'            ''eligible''     VALUE ''false'' FORMAT JSON,',
'            ''reason''       VALUE ''Order not found'',',
'            ''order_number'' VALUE :order_number',
'        ));',
'END;',
'        ',
'        }''',
'    );',
'',
'END;',
'/',
'',
'-- =============================================================',
'-- ENDPOINT 4: POST /api/conversations/inbound-message',
'--',
'-- Called by n8n Workflow A immediately after receiving a',
'-- WhatsApp message. Gets or creates a conversation record',
'-- and logs the inbound message.',
'--',
'-- Request body (JSON):',
'-- {',
'--   "channel": "whatsapp",',
'--   "customer_phone": "15149796975",',
'--   "message_sid": "SMxxxxxxx",        -- Twilio idempotency key',
'--   "message_text": "I want to return order 10452",',
'--   "media_count": 0,',
'--   "profile_name": "Michelle"         -- optional',
'-- }',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_TEMPLATE(',
'        p_module_name => ''rma_api'',',
'        p_pattern     => ''conversations/inbound-message''',
'    );',
'',
'    ORDS.DEFINE_HANDLER(',
'        p_module_name   => ''rma_api'',',
'        p_pattern       => ''conversations/inbound-message'',',
'        p_method        => ''POST'',',
'        p_source_type   => ORDS.SOURCE_TYPE_PLSQL,',
'        p_comments      => ''Log an inbound WhatsApp message and get/create a conversation'',',
'        p_source        => q''[',
'DECLARE',
'    l_body          CLOB          := :body_text;',
'    l_json          JSON_OBJECT_T;',
'    l_channel       VARCHAR2(30);',
'    l_phone         VARCHAR2(30);',
'    l_msg_sid       VARCHAR2(100);',
'    l_msg_text      VARCHAR2(4000);',
'    l_media_count   NUMBER := 0;',
'',
'    l_conv_id       conversation.conversation_id%TYPE;',
'    l_customer_id   customer.customer_id%TYPE;',
'    l_msg_id        conversation_message.message_id%TYPE;',
'    l_existing_msg  NUMBER;',
'    l_current_state conversation.current_state%TYPE;',
'    l_current_step  conversation.current_step%TYPE;',
'    l_context       conversation.context%TYPE;',
'BEGIN',
'    -- Parse request body',
'    l_json        := JSON_OBJECT_T.parse(l_body);',
'    l_channel     := NVL(l_json.get_string(''channel''),      ''whatsapp'');',
'    l_phone       := l_json.get_string(''customer_phone'');',
'    l_msg_sid     := l_json.get_string(''message_sid'');',
'    l_msg_text    := l_json.get_string(''message_text'');',
'    l_media_count := NVL(l_json.get_number(''media_count''), 0);',
'',
'    -- Idempotency: if this MessageSid was already logged, return existing',
'    SELECT COUNT(*) INTO l_existing_msg',
'    FROM   conversation_message',
'    WHERE  provider_message_id = l_msg_sid;',
'',
'    IF l_existing_msg > 0 THEN',
'        SELECT cm.message_id, cm.conversation_id',
'        INTO   l_msg_id, l_conv_id',
'        FROM   conversation_message cm',
'        WHERE  provider_message_id = l_msg_sid;',
'',
'        -- Fetch state from the conversation so n8n can route correctly',
'SELECT current_state, current_step, context',
'        INTO   l_current_state, l_current_step, l_context',
'        FROM   conversation',
'        WHERE  conversation_id = l_conv_id;',
'',
'        :status_code := 200;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(',
'            ''created''         VALUE ''false''           FORMAT JSON,',
'            ''idempotent''      VALUE ''true''            FORMAT JSON,',
'            ''conversation_id'' VALUE l_conv_id,',
'            ''message_id''      VALUE l_msg_id,',
'            ''current_state''   VALUE l_current_state,',
'            ''current_step''    VALUE l_current_step,',
'         ''context''         VALUE l_context FORMAT JSON',
'        ));',
'        RETURN;',
'    END IF;',
'',
'    -- Look up customer (may not be known yet)',
'    BEGIN',
'        SELECT customer_id INTO l_customer_id',
'        FROM   customer',
'        WHERE  mobile_phone = l_phone AND status = ''ACTIVE'';',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN l_customer_id := NULL;',
'    END;',
'',
'    -- Get or create active conversation for this phone number',
'    BEGIN',
'        SELECT conversation_id INTO l_conv_id',
'        FROM   conversation',
'        WHERE  customer_phone = l_phone',
'        AND    status         = ''ACTIVE''',
'        AND    ROWNUM         = 1',
'        ORDER BY created_on DESC;',
'',
'        -- Update last message timestamp',
'        UPDATE conversation',
'        SET    last_message_at = SYSTIMESTAMP,',
'               customer_id     = NVL(customer_id, l_customer_id)',
'        WHERE  conversation_id = l_conv_id;',
'',
'        -- Read current state AFTER update (state itself wasn''''t changed)',
'SELECT current_state, current_step, context',
'        INTO   l_current_state, l_current_step, l_context',
'        FROM   conversation',
'        WHERE  conversation_id = l_conv_id;',
'',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN',
'            INSERT INTO conversation (',
'                channel, customer_id, customer_phone,',
'                current_state, last_message_at, status',
'            ) VALUES (',
'                l_channel, l_customer_id, l_phone,',
'                ''NEW'', SYSTIMESTAMP, ''ACTIVE''',
'            )',
'            RETURNING conversation_id INTO l_conv_id;',
'',
'l_current_state := ''NEW'';',
'            l_current_step  := NULL;',
'            l_context       := NULL;',
'    END;',
'',
'    -- Log the inbound message',
'    INSERT INTO conversation_message (',
'        conversation_id, direction, provider_message_id,',
'        message_text, media_flag, raw_payload_json',
'    ) VALUES (',
'        l_conv_id, ''INBOUND'', l_msg_sid,',
'        l_msg_text,',
'        CASE WHEN l_media_count > 0 THEN ''Y'' ELSE ''N'' END,',
'        l_body',
'    )',
'    RETURNING message_id INTO l_msg_id;',
'',
'',
'',
'    :status_code := 201;',
'    OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'    HTP.PRN(JSON_OBJECT(',
'        ''created''         VALUE ''true''            FORMAT JSON,',
'        ''conversation_id'' VALUE l_conv_id,',
'        ''message_id''      VALUE l_msg_id,',
'        ''customer_id''     VALUE l_customer_id,',
'        ''customer_known''  VALUE',
'            CASE WHEN l_customer_id IS NOT NULL',
'                 THEN ''true'' ELSE ''false'' END     FORMAT JSON,',
'        ''current_state''   VALUE l_current_state,',
'        ''current_step''    VALUE l_current_step,',
'        ''context''         VALUE l_context         FORMAT JSON',
'    ));',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        ROLLBACK;',
'        :status_code := 500;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(',
'            ''error''   VALUE ''true''    FORMAT JSON,',
'            ''message'' VALUE SQLERRM',
'        ));',
'END;',
'        ',
'        ]''',
'    );',
'',
'END;',
'/',
'',
'-- =============================================================',
'-- ENDPOINT 5: PATCH /api/conversations/:id/state',
'--',
'-- n8n calls this to update the conversation''s current step',
'-- (e.g. "AWAITING_ORDER_NUMBER", "AWAITING_PHOTO", "COMPLETE").',
'-- Keeps conversation state in APEX, not in n8n memory.',
'--',
'-- Request body:',
'-- {',
'--   "current_state": "COLLECTING_INFO",',
'--   "current_step": "AWAITING_ORDER_NUMBER",',
'--   "pending_question": "What is your order number?"',
'-- }',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_TEMPLATE(',
'        p_module_name => ''rma_api'',',
'        p_pattern     => ''conversations/:id/state''',
'    );',
'',
'    ORDS.DEFINE_HANDLER(',
'        p_module_name   => ''rma_api'',',
'        p_pattern       => ''conversations/:id/state'',',
'        p_method        => ''PATCH'',',
'        p_source_type   => ORDS.SOURCE_TYPE_PLSQL,',
'        p_comments      => ''Update the current state and step of a conversation'',',
'        p_source        => q''[',
'DECLARE',
'    l_body      CLOB            := :body_text;',
'    l_json      JSON_OBJECT_T;',
'    l_state     VARCHAR2(50);',
'    l_step      VARCHAR2(100);',
'    l_question  VARCHAR2(500);',
'    l_conv_id   NUMBER;',
'    l_rows      NUMBER;',
'    l_context   CLOB;',
'    l_ctx_obj   JSON_OBJECT_T;',
'BEGIN',
'    -- Guard: id must be a non-empty number',
'    BEGIN',
'        l_conv_id := TO_NUMBER(:id);',
'    EXCEPTION',
'        WHEN VALUE_ERROR OR INVALID_NUMBER THEN',
'            :status_code := 400;',
'            OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'            HTP.PRN(JSON_OBJECT(',
'                ''error''   VALUE ''true'' FORMAT JSON,',
unistr('                ''message'' VALUE ''conversation id is missing or not a number \2014 received: '' || NVL(:id, ''(null)'')'),
'            ));',
'            RETURN;',
'    END;',
'',
'    l_json     := JSON_OBJECT_T.parse(l_body);',
'    l_state    := l_json.get_string(''current_state'');',
'    l_step     := l_json.get_string(''current_step'');',
'    l_question := l_json.get_string(''pending_question'');',
'',
'    IF l_json.has(''context'') THEN',
'        l_ctx_obj := l_json.get_object(''context'');',
'        IF l_ctx_obj IS NOT NULL THEN',
'            l_context := l_ctx_obj.to_clob();   -- serialize to JSON text',
'        END IF;',
'    END IF;',
'',
'UPDATE conversation',
'    SET    current_state    = NVL(l_state,    current_state),',
'           current_step     = NVL(l_step,     current_step),',
'           pending_question = l_question,',
'           context          = JSON_MERGEPATCH(NVL(context, ''{}''),',
'                                              NVL(l_context, ''{}'')',
'                                              RETURNING CLOB),',
'           last_message_at  = SYSTIMESTAMP',
'    WHERE  conversation_id  = l_conv_id;',
'',
'    l_rows := SQL%ROWCOUNT;',
'',
'',
'    IF l_rows = 0 THEN',
'        :status_code := 404;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(''error'' VALUE ''Conversation not found''));',
'    ELSE',
'        :status_code := 200;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(',
'            ''updated''         VALUE ''true''  FORMAT JSON,',
'            ''conversation_id'' VALUE l_conv_id,',
'            ''current_state''   VALUE l_state,',
'            ''current_step''    VALUE l_step',
'        ));',
'    END IF;',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        ROLLBACK;',
'        :status_code := 500;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(''error'' VALUE SQLERRM));',
'END;',
'        ',
'        ]''',
'    );',
'',
'END;',
'/',
'',
'-- =============================================================',
'-- ENDPOINT 6: POST /api/events/audit',
'--',
'-- Called by n8n to log every significant workflow step.',
'-- Critical for the demo: this is what populates the audit',
'-- timeline in the APEX Return Case Workbench.',
'--',
'-- Request body:',
'-- {',
'--   "correlation_id": "SM74f3d3a27f83163e44c87000826e42ce",',
'--   "event_type":     "CUSTOMER_IDENTIFIED",',
'--   "event_source":   "N8N",',
'--   "related_entity_type": "CONVERSATION",',
'--   "related_entity_id":   42,',
'--   "outcome_status": "SUCCESS",',
'--   "request_payload":  { ... },',
'--   "response_payload": { ... }',
'-- }',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_TEMPLATE(',
'        p_module_name => ''rma_api'',',
'        p_pattern     => ''events/audit''',
'    );',
'',
'    ORDS.DEFINE_HANDLER(',
'        p_module_name   => ''rma_api'',',
'        p_pattern       => ''events/audit'',',
'        p_method        => ''POST'',',
'        p_source_type   => ORDS.SOURCE_TYPE_PLSQL,',
'        p_comments      => ''Log a workflow audit event from n8n'',',
'        p_source        => q''[',
'DECLARE',
'    l_body      CLOB  := :body_text;',
'    l_event_id  workflow_event.workflow_event_id%TYPE;',
'    l_entity_id NUMBER;',
'BEGIN',
'    -- Use JSON_VALUE() throughout to avoid ORA-40573 with PL/SQL JSON types.',
'    -- JSON_VALUE handles both quoted strings and bare numbers from n8n expressions.',
'    l_entity_id := TO_NUMBER(JSON_VALUE(l_body, ''$.related_entity_id''));',
'',
'    INSERT INTO workflow_event (',
'        correlation_id,',
'        related_entity_type,',
'        related_entity_id,',
'        event_type,',
'        event_source,',
'        request_payload,',
'        response_payload,',
'        outcome_status,',
'        error_message',
'    ) VALUES (',
'        JSON_VALUE(l_body, ''$.correlation_id''),',
'        JSON_VALUE(l_body, ''$.related_entity_type''),',
'        l_entity_id,',
'        JSON_VALUE(l_body, ''$.event_type''),',
'        NVL(JSON_VALUE(l_body, ''$.event_source''),   ''N8N''),',
'        JSON_VALUE(l_body, ''$.request_payload''),',
'        JSON_VALUE(l_body, ''$.response_payload''),',
'        NVL(JSON_VALUE(l_body, ''$.outcome_status''), ''SUCCESS''),',
'        JSON_VALUE(l_body, ''$.error_message'')',
'    )',
'    RETURNING workflow_event_id INTO l_event_id;',
'',
'',
'',
'    :status_code := 201;',
'    OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'    HTP.PRN(JSON_OBJECT(',
'        ''created''           VALUE ''true'' FORMAT JSON,',
'        ''workflow_event_id'' VALUE l_event_id',
'    ));',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
';',
'        :status_code := 500;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(''error'' VALUE SQLERRM));',
'END;',
'        ',
'        ]''',
'    );',
'',
'END;',
'/',
'',
'',
'-- =============================================================',
'-- ENDPOINT 6: POST /api/conversations/outbound-message',
'--',
'-- Called by n8n Workflow A immediately after receiving a',
'-- WhatsApp message. Gets or creates a conversation record',
'-- and logs the inbound message.',
'--',
'-- Request body (JSON):',
'-- {',
'--   "channel": "whatsapp",',
'--   "customer_phone": "15149796975",',
'--   "message_sid": "SMxxxxxxx",        -- Twilio idempotency key',
'--   "message_text": "I want to return order 10452",',
'--   "media_count": 0,',
'--   "profile_name": "Michelle"         -- optional',
'-- }',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_TEMPLATE(',
'        p_module_name => ''rma_api'',',
'        p_pattern     => ''conversations/outbound-message''',
'    );',
'',
'    ORDS.DEFINE_HANDLER(',
'        p_module_name   => ''rma_api'',',
'        p_pattern       => ''conversations/outbound-message'',',
'        p_method        => ''POST'',',
'        p_source_type   => ORDS.SOURCE_TYPE_PLSQL,',
'        p_comments      => ''Log an outbound WhatsApp message and get/create a conversation'',',
'        p_source        => q''[',
'DECLARE',
'  l_body          VARCHAR2(32767) := :body_text;',
'  l_json          JSON_OBJECT_T;',
'  l_conv_id       VARCHAR2(100);',
'  l_message_text  VARCHAR2(32767);',
'  l_message_sid   VARCHAR2(100);',
'  l_msg_id        NUMBER;',
'BEGIN',
'  -- Parse JSON body (:body_text is VARCHAR2; :body is BLOB and cannot be',
unistr('  -- assigned to CLOB directly \2014 ORDS raises PLS-00382 if you try)'),
'  l_json         := JSON_OBJECT_T.parse(l_body);',
'  l_conv_id      := l_json.get_string(''conversation_id'');',
'  l_message_text := l_json.get_string(''message_text'');',
'',
'  -- Insert outbound message',
'  INSERT INTO conversation_message (',
'    conversation_id,',
'    direction,',
'    message_text,',
'    created_on',
'  ) VALUES (',
'    TO_NUMBER(l_conv_id),',
'    ''OUTBOUND'',',
'    l_message_text,',
'    SYSTIMESTAMP',
'  )',
'  RETURNING message_id INTO l_msg_id;',
'',
'  -- Keep last_message_at current on the parent conversation',
'  UPDATE conversation',
'  SET    last_message_at = SYSTIMESTAMP',
'  WHERE  conversation_id = TO_NUMBER(l_conv_id);',
'',
'',
'',
'  -- Return success',
'  APEX_JSON.open_object;',
'  APEX_JSON.write(''status'',     ''ok'');',
'  APEX_JSON.write(''message_id'', l_msg_id);',
'  APEX_JSON.close_object;',
'',
'EXCEPTION',
'  WHEN OTHERS THEN',
'    ROLLBACK;',
'    :status := 500;',
'    APEX_JSON.open_object;',
'    APEX_JSON.write(''status'',  ''error'');',
'    APEX_JSON.write(''message'', SQLERRM);',
'    APEX_JSON.close_object;',
'END;',
'        ',
'        ]''',
'    );',
'',
'END;',
'/',
'',
'',
'',
'-- =============================================================',
'-- ENDPOINT 4: POST /api/returns',
'--',
'-- Create a return case (RMA). Idempotent via idempotency_key.',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_TEMPLATE(',
'        p_module_name => ''rma_api'',',
'        p_pattern     => ''returns''',
'    );',
'',
'    ORDS.DEFINE_HANDLER(',
'        p_module_name   => ''rma_api'',',
'        p_pattern       => ''returns'',',
'        p_method        => ''POST'',',
'        p_source_type   => ORDS.SOURCE_TYPE_PLSQL,',
'        p_comments      => ''Create an RMA'',',
'        p_source        => q''[',
'DECLARE',
'    l_body              CLOB    := :body_text;',
'',
'    l_customer_id       return_case.customer_id%TYPE;',
'    l_order_id          return_case.order_id%TYPE;',
'    l_conversation_id   return_case.conversation_id%TYPE;',
'    l_correlation_id    return_case.correlation_id%TYPE;',
'    l_idempotency_key   return_case.idempotency_key%TYPE;',
'    l_reason_code       return_case.reason_code%TYPE;',
'    l_description       return_case.customer_description%TYPE;',
'    l_resolution        return_case.requested_resolution%TYPE;',
'    l_channel           return_case.channel%TYPE;',
'',
'    l_return_case_id    return_case.return_case_id%TYPE;',
'    l_rma_number        return_case.rma_number%TYPE;',
'    l_req_approval      return_case.approval_required_flag%TYPE := ''N'';',
'    l_order_total       sales_order.order_total%TYPE;',
'    l_existing_id       return_case.return_case_id%TYPE;',
'',
'    c_approval_threshold CONSTANT NUMBER := 500;',
'BEGIN',
'    -- Parse all fields from request body using JSON_VALUE',
'    l_customer_id     := TO_NUMBER(JSON_VALUE(l_body, ''$.customer_id''));',
'    l_order_id        := TO_NUMBER(JSON_VALUE(l_body, ''$.order_id''));',
'    l_conversation_id := TO_NUMBER(JSON_VALUE(l_body, ''$.conversation_id''));',
'    l_correlation_id  := JSON_VALUE(l_body, ''$.correlation_id'');',
'    l_idempotency_key := JSON_VALUE(l_body, ''$.idempotency_key'');',
'    l_reason_code     := JSON_VALUE(l_body, ''$.reason_code'');',
'    l_description     := JSON_VALUE(l_body, ''$.customer_description'');',
'    l_resolution      := JSON_VALUE(l_body, ''$.requested_resolution'');',
'    l_channel         := NVL(JSON_VALUE(l_body, ''$.channel''), ''WHATSAPP'');',
'',
'    -- Validate required fields',
'    IF l_customer_id IS NULL THEN',
'       -- :status_code := 422;',
'      --  OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'       -- HTP.PRN(JSON_OBJECT(''error'' VALUE ''true'' FORMAT JSON,',
'       --                     ''message'' VALUE ''customer_id is required''));',
'       -- RETURN;',
'        select customer_id into l_customer_id',
'        from SALES_order',
'        where order_id=TO_NUMBER(JSON_VALUE(l_body, ''$.'))
);
wwv_flow_imp_shared.append_to_install_script(
 p_id=>wwv_flow_imp.id(19898637377693667)
,p_script_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'order_id''));',
'',
'    END IF;',
'',
'    IF l_idempotency_key IS NULL THEN',
'        :status_code := 422;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(''error'' VALUE ''true'' FORMAT JSON,',
'                            ''message'' VALUE ''idempotency_key is required''));',
'        RETURN;',
'    END IF;',
'',
'    -- Idempotency check: return existing record if key already used',
'    BEGIN',
'        SELECT return_case_id, rma_number',
'        INTO   l_existing_id, l_rma_number',
'        FROM   return_case',
'        WHERE  idempotency_key = l_idempotency_key;',
'',
unistr('        -- Already exists \2014 return it without creating a duplicate'),
'        :status_code := 200;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(',
'            ''created''        VALUE ''false''       FORMAT JSON,',
'            ''idempotent''     VALUE ''true''        FORMAT JSON,',
'            ''return_case_id'' VALUE l_existing_id,',
'            ''rma_number''     VALUE l_rma_number',
'        ));',
'        RETURN;',
'    EXCEPTION',
'        WHEN NO_DATA_FOUND THEN NULL;  -- expected path: key not seen before',
'    END;',
'',
'    -- Check if high-value order requires manager approval',
'    IF l_order_id IS NOT NULL THEN',
'        BEGIN',
'            SELECT order_total INTO l_order_total',
'            FROM   sales_order',
'            WHERE  order_id = l_order_id;',
'',
'            IF l_order_total >= c_approval_threshold THEN',
'                l_req_approval := ''Y'';',
'            END IF;',
'        EXCEPTION',
'            WHEN NO_DATA_FOUND THEN NULL;',
'        END;',
'    END IF;',
'',
'    -- Create the return case',
'    INSERT INTO return_case (',
'        customer_id,',
'        order_id,',
'        conversation_id,',
'        correlation_id,',
'        idempotency_key,',
'        channel,',
'        case_status,',
'        reason_code,',
'        customer_description,',
'        requested_resolution,',
'        approval_required_flag,',
'        approval_status,',
'        created_by_source',
'    ) VALUES (',
'        l_customer_id,',
'        l_order_id,',
'        l_conversation_id,',
'        l_correlation_id,',
'        l_idempotency_key,',
'        l_channel,',
'        CASE WHEN l_req_approval = ''Y'' THEN ''PENDING_APPROVAL'' ELSE ''OPEN'' END,',
'        l_reason_code,',
'        l_description,',
'        l_resolution,',
'        l_req_approval,',
'        CASE WHEN l_req_approval = ''Y'' THEN ''PENDING'' ELSE NULL END,',
'        ''WHATSAPP_BOT''',
'    )',
'    RETURNING return_case_id, rma_number INTO l_return_case_id, l_rma_number;',
'',
'    -- Link the conversation to this return case',
'    IF l_conversation_id IS NOT NULL THEN',
'        UPDATE conversation',
'        SET    open_return_case_id = l_return_case_id,',
'               current_state       = CASE WHEN l_req_approval = ''Y''',
'                                          THEN ''PENDING_APPROVAL''',
'                                          ELSE ''COMPLETE'' END',
'        WHERE  conversation_id = l_conversation_id;',
'    END IF;',
'',
'',
'',
'    :status_code := 201;',
'    OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'    HTP.PRN(JSON_OBJECT(',
'        ''created''              VALUE ''true''        FORMAT JSON,',
'        ''return_case_id''       VALUE l_return_case_id,',
'        ''rma_number''           VALUE l_rma_number,',
'        ''case_status''          VALUE CASE WHEN l_req_approval = ''Y''',
'                                          THEN ''PENDING_APPROVAL''',
'                                          ELSE ''OPEN'' END,',
'        ''requires_approval''    VALUE CASE WHEN l_req_approval = ''Y''',
'                                          THEN ''true'' ELSE ''false'' END FORMAT JSON,',
'        ''requested_resolution'' VALUE l_resolution,',
'        ''channel''              VALUE l_channel',
'    ));',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        ROLLBACK;',
'        :status_code := 500;',
'        OWA_UTIL.MIME_HEADER(''application/json'', TRUE);',
'        HTP.PRN(JSON_OBJECT(',
'            ''error''   VALUE ''true'' FORMAT JSON,',
'            ''message'' VALUE SQLERRM',
'        ));',
'END;',
'        ',
'        ',
'        ]''',
'    );',
'   ',
'END;',
'/',
'',
'',
'',
'-- =============================================================',
'-- ENDPOINT 8: POST /api/returns/:id/approve',
'--',
'-- ',
'-- =============================================================',
'BEGIN',
'    ORDS.DEFINE_TEMPLATE(',
'        p_module_name => ''rma_api'',',
'        p_pattern     => ''returns/:id/approve''',
'    );',
'',
'    ORDS.DEFINE_HANDLER(',
'        p_module_name   => ''rma_api'',',
'        p_pattern       => ''returns/:id/approve'',',
'        p_method        => ''POST'',',
'        p_source_type   => ORDS.SOURCE_TYPE_PLSQL,',
'        p_comments      => ''Approve the RMA'',',
'        p_source        => q''|',
'',
'',
'DECLARE',
'  l_id          NUMBER        := :id;',
'  l_rma         VARCHAR2(64)  := :rma_number;',
'  l_approved_by VARCHAR2(128) := NVL(:approved_by, ''auto-n8n'');',
'  l_rows        NUMBER;',
'BEGIN',
'  -- Only transition rows not already approved -> idempotent on retry',
'  UPDATE return_case',
'     SET case_status        = ''CLOSED'',',
'     approval_status=''APPROVED''',
'   WHERE nvl(approval_status,''N'')!=''APPROVED'' and return_case_id = l_id;',
'',
'  l_rows := SQL%ROWCOUNT;',
'',
'  -- Audit only on an actual transition',
'  IF l_rows = 1 THEN',
'    INSERT INTO workflow_event (',
'        related_entity_type,',
'        related_entity_id,',
'        event_type,',
'        event_source,',
'        request_payload,',
'        outcome_status',
'    ) VALUES (',
'        ''RETURN_CASE'',',
'        l_id,',
'        ''APPROVED'',',
'        ''N8N'',',
'        ''{"rma_number":"'' || l_rma || ''","approved_by":"'' || l_approved_by || ''"}'',',
'        ''SUCCESS''',
'    );',
'  END IF;',
'',
'  IF l_rows = 0 THEN',
unistr('    -- Either already approved (retry) or id not found \2014 distinguish'),
'    SELECT COUNT(*) INTO l_rows FROM return_case WHERE return_case_id = l_id;',
'    IF l_rows = 0 THEN',
'      :status_code := 404;',
'      htp.p(''{"status":"error","message":"return not found"}'');',
'      RETURN;',
'    END IF;',
'  END IF;',
'',
'  :status_code := 200;',
'  htp.p(''{"status":"ok","id":'' || l_id ||',
'        '',"rma_number":"'' || l_rma || ''","state":"APPROVED"}'');',
'EXCEPTION',
'  WHEN OTHERS THEN',
'    ROLLBACK;',
'    DECLARE',
'      l_err VARCHAR2(2000) := SUBSTR(SQLERRM, 1, 2000);',
'    BEGIN',
'      INSERT INTO workflow_event (',
'          related_entity_type,',
'          related_entity_id,',
'          event_type,',
'          event_source,',
'          outcome_status,',
'          error_message',
'      ) VALUES (',
'          ''RETURN_CASE'',',
'          l_id,',
'          ''APPROVE_FAILED'',',
'          ''N8N'',',
'          ''FAILURE'',',
'          l_err',
'      );',
'   ',
'    END;',
'    :status_code := 500;',
'    htp.p(''{"status":"error","message":"'' ||',
'          REPLACE(SQLERRM,''"'','''''''') || ''"}'');',
'END;',
'',
'        ',
'        |''',
'    );',
'',
'END;',
'/'))
);
end;
